import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { FavoritesService } from '../../../../core/services/favorites.service';
import { ExportService } from '../../../../core/services/export.service';
import { CidadeFavorita } from '../../../../core/models/models';

@Component({
  selector: 'app-favorites-list',
  templateUrl: './favorites-list.component.html',
  styleUrls: ['./favorites-list.component.scss'],
})
export class FavoritesListComponent implements OnInit {
  favorites: CidadeFavorita[] = [];
  loading    = false;
  error      = '';
  successMsg = '';
  showForm   = false;
  editId: number | null = null;

  form: FormGroup;

  constructor(
    private favSvc: FavoritesService,
    private exportSvc: ExportService,
    private fb: FormBuilder,
  ) {
    this.form = this.fb.group({
      nome_cidade: ['', Validators.required],
      pais:        ['', [Validators.required, Validators.maxLength(5)]],
    });
  }

  ngOnInit(): void { this.load(); }

  load(): void {
    this.loading = true;
    this.favSvc.getAll().subscribe({
      next:  (r) => { this.favorites = r.data ?? []; this.loading = false; },
      error: ()  => this.loading = false,
    });
  }

  openAdd(): void { this.editId = null; this.form.reset(); this.showForm = true; }

  openEdit(fav: CidadeFavorita): void {
    this.editId = fav.id;
    this.form.patchValue({ nome_cidade: fav.nome_cidade, pais: fav.pais });
    this.showForm = true;
  }

  save(): void {
    if (this.form.invalid) return;
    const { nome_cidade, pais } = this.form.value;

    const action = this.editId
      ? this.favSvc.update(this.editId, nome_cidade, pais)
      : this.favSvc.add(nome_cidade, pais);

    action.subscribe({
      next: () => {
        this.successMsg = this.editId ? 'Cidade actualizada!' : 'Cidade adicionada!';
        this.showForm = false;
        this.load();
      },
      error: (e) => this.error = e.error?.message ?? 'Erro.',
    });
  }

  remove(id: number): void {
    if (!confirm('Remover esta cidade dos favoritos?')) return;
    this.favSvc.remove(id).subscribe({
      next: () => { this.successMsg = 'Cidade removida.'; this.load(); },
      error: (e) => this.error = e.error?.message,
    });
  }

  exportCSV(): void { this.exportSvc.exportFavoritasCSV(this.favorites); }
  exportPDF(): void { this.exportSvc.exportFavoritasPDF(this.favorites, ''); }
}
<div class="page-container">
  <div class="page-header">
    <h1>{{ 'favorites.title' | translate }}</h1>
    <div class="page-actions">
      <app-export-panel (exportCSV)="exportCSV()" (exportPDF)="exportPDF()"></app-export-panel>
      <button class="btn btn-primary" (click)="openAdd()">
        ➕ {{ 'favorites.add' | translate }}
      </button>
    </div>
  </div>

  <app-alert [message]="error"      type="error"   (dismiss)="error=''"></app-alert>
  <app-alert [message]="successMsg" type="success" (dismiss)="successMsg=''"></app-alert>

  <!-- Add/Edit form -->
  <div class="modal-overlay" *ngIf="showForm" (click)="showForm=false">
    <div class="modal" (click)="$event.stopPropagation()">
      <h2 class="modal-title">{{ editId ? 'Editar' : 'Adicionar' }} Cidade</h2>
      <form [formGroup]="form" (ngSubmit)="save()">
        <div class="field">
          <label>Cidade</label>
          <input type="text" formControlName="nome_cidade" placeholder="Ex: Luanda">
        </div>
        <div class="field">
          <label>País (código)</label>
          <input type="text" formControlName="pais" placeholder="Ex: AO" maxlength="5">
        </div>
        <div class="modal-actions">
          <button type="button" class="btn btn-secondary" (click)="showForm=false">
            {{ 'common.cancel' | translate }}
          </button>
          <button type="submit" class="btn btn-primary" [disabled]="form.invalid">
            {{ 'common.save' | translate }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <app-loading-spinner [loading]="loading"></app-loading-spinner>

  <div class="favorites-grid" *ngIf="!loading">
    <div class="favorite-card" *ngFor="let fav of favorites">
      <div class="fav-card__body">
        <div class="fav-card__icon">🌍</div>
        <div class="fav-card__info">
          <h3>{{ fav.nome_cidade }}</h3>
          <span class="country-badge">{{ fav.pais }}</span>
          <p class="fav-date">Adicionada {{ fav.adicionada_em | date:'dd/MM/yyyy' }}</p>
        </div>
      </div>
      <div class="fav-card__actions">
        <button class="btn-icon btn-edit" (click)="openEdit(fav)" title="Editar">✏️</button>
        <button class="btn-icon btn-del" (click)="remove(fav.id)" title="Remover">🗑️</button>
      </div>
    </div>

    <div class="empty-state" *ngIf="!favorites.length">
      <div class="empty-icon">⭐</div>
      <p>{{ 'common.noData' | translate }}</p>
      <button class="btn btn-primary" (click)="openAdd()">Adicionar primeira cidade</button>
    </div>
  </div>
</div>
